WITH lapsed_cohort AS (
  -- Lapsed customers: last order >90 days before period start
  SELECT customer_id FROM orders WHERE order_date <= DATEADD(day, -90, {start_date}) AND order_date >= DATEADD(day, -365, {start_date}) GROUP BY customer_id HAVING MAX(order_date) <= DATEADD(day, -90, {start_date})
),
reactivated AS (
  SELECT DISTINCT o.customer_id FROM orders o JOIN lapsed_cohort l ON o.customer_id = l.customer_id WHERE o.order_date BETWEEN {start_date} AND {end_date}
),
cohort_size AS (
  SELECT COUNT(DISTINCT customer_id) AS lapsed_customers FROM lapsed_cohort
)
SELECT COALESCE(COUNT(DISTINCT r.customer_id), 0) AS reactivated_customers, cs.lapsed_customers, COALESCE(COUNT(DISTINCT r.customer_id), 0) * 100.0 / NULLIF(cs.lapsed_customers, 0) AS win_back_rate FROM reactivated r, cohort_size cs

WITH first_orders AS (
  SELECT customer_id, MIN(order_date) AS first_order_date FROM orders WHERE status = 'completed' GROUP BY customer_id HAVING MIN(order_date) BETWEEN {start_date} AND {end_date}
),
second_orders AS (
  SELECT customer_id, MIN(order_date) AS second_order_date FROM orders WHERE status = 'completed' AND order_date > first_order_date GROUP BY customer_id
),
converted AS (
  SELECT s.customer_id FROM first_orders f JOIN second_orders s ON f.customer_id = s.customer_id WHERE s.second_order_date <= DATEADD(day, {conversion_window_days}, f.first_order_date)
)
SELECT COUNT(DISTINCT c.customer_id) AS converted_customers, COUNT(DISTINCT f.customer_id) AS first_orders, COUNT(DISTINCT c.customer_id) * 100.0 / NULLIF(COUNT(DISTINCT f.customer_id), 0) AS conversion_rate FROM converted c, first_orders f

WITH customer_revenue AS (
  SELECT customer_id, SUM(net_revenue) AS total_revenue FROM net_revenue_daily GROUP BY customer_id
),
ranked AS (
  SELECT customer_id, total_revenue, NTILE(10) OVER (ORDER BY total_revenue DESC) AS decile FROM customer_revenue
),
top_decile AS (
  SELECT SUM(total_revenue) AS top_10_revenue FROM ranked WHERE decile = 1
),
total_revenue AS (
  SELECT SUM(total_revenue) AS all_revenue FROM customer_revenue
)
SELECT tr.top_10_revenue, t.total_revenue, tr.top_10_revenue * 100.0 / NULLIF(t.total_revenue, 0) AS concentration_risk FROM top_decile tr, total_revenue t
